using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Define uma área/sala do jogo para uso em condições de NPC (área actual,
/// visitada, mortes na área), no banner de nome de área da câmara e no sistema
/// de save (autosave ao entrar/sair de área ou cidade — ver "isCity").
/// </summary>
[CreateAssetMenu(menuName = "Animals/Area Data", fileName = "NewArea")]
public class AreaData : ScriptableObject
{
    /// <summary>
    /// Tipo de nó desta área no Mapa-Múndi (Tarefa Mapa-Múndi). Determina como o
    /// <c>WorldMapController</c> trata o custo de desbloqueio e a apresentação:
    /// <list type="bullet">
    /// <item><description><b>Normal</b>: nó comum — custo definido em <see cref="unlockCost"/> (a 1ª área de cada mundo deve ter <c>unlockCost = 1</c>).</description></item>
    /// <item><description><b>Vila</b>: custo sempre 0 — desbloqueada automaticamente junto com a área anterior que abre o caminho até ela.</description></item>
    /// <item><description><b>Boss</b>: custo sempre 0 e nunca "comprável" — o nó só fica acessível depois de a missão principal do mundo ser concluída (sequência de desbloqueio especial, ver <c>WorldMapController</c>).</description></item>
    /// </list>
    /// </summary>
    public enum MapNodeType
    {
        Normal,
        Vila,
        Boss
    }

    [Header("Identidade")]
    public string areaId;
    public string displayName;

    [Header("Mundo")]
    public WorldData world;

    [Header("Cenas (Tarefa #31 — Configuração de Cenas)")]
    [Tooltip("Nome da cena Unity (Build Settings) onde esta área vive. Usado por SceneLoader/AreaManager para carregar esta área a partir de uma AreaTransition.")]
    public string sceneName;

    [Tooltip("IDs de AreaSpawnPoint existentes na cena desta área (ex: \"EntradaOeste\", \"EntradaLeste\", \"CheckpointPrincipal\") — apenas para referência ao configurar AreaTransition.targetSpawnPointId; os pontos em si são componentes AreaSpawnPoint colocados na cena, não referências directas a Transforms.")]
    public List<string> spawnPointIds = new List<string>();

    [Header("Save")]
    [Tooltip("Marca esta área como uma cidade/vila. Não muda a lógica de autosave por si só (qualquer mudança de área já dispara autosave), mas permite distinguir 'entrar/sair de uma cidade' para outros sistemas (ex: música, UI).")]
    public bool isCity;

    [Header("Menu de Pausa — Área Atual")]
    [Tooltip("Descrição atmosférica curta da área, mostrada na secção \"Área Atual\" do Menu de Pausa.")]
    [TextArea] public string description;

    [Tooltip("Ilustração ambiente da área (árvores, ruínas, gelo, coral, bambu, etc.), mostrada do lado direito da secção \"Área Atual\".")]
    public Sprite illustration;

    [Header("Descobertas — Totais da Área")]
    [Tooltip("Número total de Runas de Gaia existentes nesta área.")]
    public int totalRunas;

    [Tooltip("Número total de NPCs para resgatar nesta área.")]
    public int totalNpcsToRescue;

    [Tooltip("Número total de Sussurros da Terra existentes nesta área.")]
    public int totalWhispers;

    [Tooltip("Número total de baús existentes nesta área.")]
    public int totalChests;

    [Tooltip("Número total de Fragmentos Vitais existentes nesta área.")]
    public int totalFragments;

    [Tooltip("Número total de Ecos Perdidos existentes nesta área (0 em áreas de Vila e Boss). Recomendado: 15 por área normal, pois os 5 Sussurros têm preços 1+2+3+4+5 = 15 Ecos Perdidos.")]
    public int totalEcosPerdidos;

    [Tooltip("Número total de Melodias Selvagens existentes nesta área (0 = nenhuma). Conta para a percentagem de conclusão da área e do save.")]
    public int totalMelodies;

    [Header("Desafio Opcional")]
    [Tooltip("Esta área tem um desafio opcional (ex: portal de desafio)? Conta para a percentagem de conclusão da área.")]
    public bool hasOptionalChallenge;

    [Header("Animal Libertado")]
    [Tooltip("Forma animal libertada nesta área (se houver). Mostrado em \"Área Atual\" como \"Animal libertado\" e conta para a percentagem de conclusão.")]
    public AnimalFormData freedAnimalForm;

    [Header("Mapa-Múndi — Nó")]
    [Tooltip("Tipo de nó desta área no Mapa-Múndi. Ver comentário do enum MapNodeType para detalhes de cada tipo.")]
    public MapNodeType mapNodeType = MapNodeType.Normal;

    [Tooltip("Custo em Runas de Gaia para desbloquear esta área (botão \"Desbloquear\" no painel do Mapa-Múndi). A 1ª área de cada mundo deve ter custo 1 (regra do GDD: \"todos os mundos disponíveis desde o início, mas a 1ª área de cada um custa 1 Runa\"). Ignorado (tratado como 0) se mapNodeType for Vila ou Boss.")]
    [Min(0)]
    public int unlockCost;

    [Header("Mapa-Múndi — Área de Boss (mapNodeType = Boss)")]
    [Tooltip("Nome do boss, mostrado no painel apenas DEPOIS do primeiro encontro (vitória ou derrota). Antes disso o painel mostra \"????????\".")]
    public string bossDisplayName;

    [Tooltip("Quantidade de Runas de Gaia dadas como recompensa ao derrotar este boss (mostrado no painel como \"Recompensa: X Runas de Gaia\").")]
    [Min(0)]
    public int bossRunasReward = 5;

    [Tooltip("Emblema obtido ao derrotar este boss — \"????????\" no painel até a vitória, depois mostra este emblema.")]
    public EmblemData bossEmblem;
}
